import sys

class Solution:
    def isPrime(self, n):
        if n <= 1:
            return False
        if n <= 3:
            return True
        if n % 2 == 0 or n % 3 == 0:
            return False
        i = 5
        while i * i <= n:
            if n % i == 0 or n % (i + 2) == 0:
                return False
            i += 6
        return True

# test the function
if __name__ == '__main__':
    n = int(sys.stdin.readline().strip())
    print(Solution().isPrime(n))

